class Solution {
    public int smallestRepunitDivByK(int k) {
        if (k % 2 == 0 || k % 5 == 0) return -1;
        int res = 1;
        while (true) {
            int n = res;
            while (n % 10 > 0) {
                n = n % 10 + n / 10;
            }
            if (n % k == 0) return res.length();
            res++;
        }
    }
}
